parsed.api_descriptions:
API_name: nchu_course_search_across_semesters
Description:
{
  "description": "Search for courses across multiple semesters. Useful for finding historical course offerings. Note: This may be slow if searching all semesters as it loads data on demand. JSON string containing search results grouped by semester",
  "required_parameters": [
    {
      "name": "keyword",
      "type": "STRING",
      "description": "Search keyword (course name, teacher name, etc.)"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit_per_semester",
      "type": "NUMBER",
      "description": "Maximum number of results per semester (default: 10)",
      "default": 10
    },
    {
      "name": "search_fields",
      "type": "STRING",
      "description": "Comma-separated fields to search in (default: 科目名稱,上課教師,開課單位)",
      "default": null
    },
    {
      "name": "semesters",
      "type": "STRING",
      "description": "Comma-separated semester codes to search (e.g., \"1142,1141,1132\"). If not specified, searches all available semesters.",
      "default": null
    }
  ]
}

